#include <stdio.h>
int countStudents(int arr[], int n, int pages) {
    int students = 1;
    int pagesStudent = 0;
    for (int i = 0; i < n; i++) {
        if (pagesStudent + arr[i] <= pages) {
            pagesStudent += arr[i];
        } else {
            students++;
            pagesStudent = arr[i];
        }
    }
    return students;
}

int findPages(int arr[], int n, int m) {
    if (m > n) return -1;
    int low = arr[0];
    int high = 0;
    for (int i = 0; i < n; i++) {
        if (arr[i] > low) low = arr[i];
        high += arr[i];
    }
    for (int pages = low; pages <= high; pages++) {
        if (countStudents(arr, n, pages) == m) {
            return pages;
        }
    }
    return low;
}

